/* ---------------------------------------------------------------------------
 * tokens.css — operator's portfolio
 * Canonical custom properties. Consumed by every component.
 * Dark is canonical; light is opt-in (toggle implemented separately).
 * --------------------------------------------------------------------------- */

:root,
:root[data-theme="dark"] {
  /* ----- v2 semantic colour palette (suite 13/P02) -----
     Dark is canonical. Hex with alpha (#RRGGBBAA) keeps tokens
     self-contained — no rgba(). All fg/bg pairs documented in
     docs/v2_audit.md ## Contrast deviations meet WCAG AA. */

  /* surface */
  --bg:           #0c0e10;            /* base background          */
  --bg-mute:      #14171a;            /* muted surface            */
  --bg-raise:     #1b1f23;            /* raised surface (cards)   */
  --bg-overlay:   #06070824;          /* modal overlay            */

  /* foreground */
  --fg:           #e8e6e1;            /* primary text             */
  --fg-mute:      #8b8a85;            /* secondary text           */
  --fg-faint:     #6e6e68;            /* tertiary text — adjusted from #5a5a55 to clear AA-large (see audit) */
  --fg-inverse:   #0c0e10;            /* text on accent surface   */

  /* borders + dividers */
  --line:         #232629;            /* hairline                 */
  --line-strong:  #3a3d40;            /* emphatic border          */

  /* accent — warm gold/amber inherited from v1 (B3). Do not change without authorization. */
  --accent:       #c9a96e;            /* primary accent (mono)    */
  --accent-mute:  #c9a96e22;          /* hover/wash               */
  --accent-fg:    #0c0e10;            /* text on accent           */

  /* status — used sparingly (chat error states only) */
  --warn:         #d18b3a;
  --error:        #dc6e69;            /* adjusted from #d2615c to clear AA on bg-raise (see audit) */
  --ok:           #6da16a;

  /* ----- v1 aliases (transitional) -------------------------
     Active components in src/components/* still reference v1
     names. Aliases map them onto the v2 palette so the visual
     ramp degrades gracefully until each component is migrated
     in subsequent suite-13 prompts. New code MUST consume the
     semantic v2 tokens above; do not introduce new --bg-N or
     --fg-hi/dim references. */
  --bg-0:        var(--bg);
  --bg-1:        var(--bg-mute);
  --bg-2:        var(--bg-raise);
  --bg-3:        var(--line);
  --rule:        var(--line);
  --fg-hi:       var(--fg);
  --fg-dim:      var(--fg-mute);
  --accent-dim:  var(--accent-mute);
  --danger:      var(--error);

  /* type stacks — two faces, period. mono for technical + headlines,
     serif for long-form. --font-mono / --font-serif are injected by
     next/font on <html>; the tokens below are the consumable stacks. */
  --t-mono:  var(--font-mono),  ui-monospace, monospace;
  --t-serif: var(--font-serif), Georgia, serif;

  /* type scale — base 16px, ratio 1.25, 7 steps */
  --t-sm-size:    13px;  --t-sm-lh:    20px;
  --t-base-size:  16px;  --t-base-lh:  26px;
  --t-md-size:    18px;  --t-md-lh:    28px;
  --t-lg-size:    22px;  --t-lg-lh:    32px;
  --t-xl-size:    28px;  --t-xl-lh:    36px;
  --t-2xl-size:   36px;  --t-2xl-lh:   44px;
  --t-3xl-size:   48px;  --t-3xl-lh:   56px;

  /* tracking */
  --t-tight:  -0.01em;
  --t-normal: 0;
  --t-wide:   0.05em;

  /* spacing (8px base, with 4px half-step) */
  --s-0:   0;
  --s-1:   4px;
  --s-2:   8px;
  --s-3:   12px;
  --s-4:   16px;
  --s-5:   24px;
  --s-6:   32px;
  --s-7:   48px;
  --s-8:   64px;
  --s-9:   96px;
  --s-10:  128px;

  /* borders */
  --r-0: 0;
  --r-1: 2px;
  --border-hair:   1px solid var(--rule);
  --border-double: 3px double var(--rule);

  /* z-index semantic */
  --z-rail:      40;
  --z-statusbar: 50;
  --z-palette:   80;
  --z-toast:     90;
  --z-boot:     100;

  /* duration + easing */
  --d-flash: 120ms;
  --d-fast:  160ms;
  --d-norm:  240ms;
  --d-slow:  420ms;
  --ease:    cubic-bezier(0.2, 0.0, 0.0, 1.0);

  /* R01: accordion-specific timing — longer, decelerating curve so width
     animates without snapping at rest. Reusable for any large layout move. */
  --d-accordion: 420ms;
  --ease-accordion: cubic-bezier(0.22, 1, 0.36, 1);

  /* layout */
  --statusbar-h: 0px; /* R04: status bar removed; reserved height collapses */
  --toprail-h:   32px;
  --keycap-size: 36px;
  --measure-prose: 72ch;
  --measure-book:  64ch;

  color-scheme: dark;
}

/* light: explicit attribute override of dark default (see B1).
   prefers-color-scheme is intentionally NOT used here so the
   theme toggle (suite 14/P07) can override the OS preference. */
:root[data-theme="light"] {
  /* surface */
  --bg:           #fbfaf8;
  --bg-mute:      #f1efeb;
  --bg-raise:     #ffffff;
  --bg-overlay:   #00000018;

  /* foreground */
  --fg:           #1a1a1a;
  --fg-mute:      #555550;
  --fg-faint:     #888880;
  --fg-inverse:   #fbfaf8;

  /* borders + dividers */
  --line:         #e3e0d8;
  --line-strong:  #c8c4b8;

  /* accent */
  --accent:       #8a6a2a;
  --accent-mute:  #8a6a2a18;
  --accent-fg:    #fbfaf8;

  /* status */
  --warn:         #a35e08;            /* adjusted from #b46a0a to clear AA normal (see audit) */
  --error:        #a73a35;
  --ok:           #3f6e3a;

  /* v1 aliases (see dark block) */
  --bg-0:        var(--bg);
  --bg-1:        var(--bg-mute);
  --bg-2:        var(--bg-raise);
  --bg-3:        var(--line);
  --rule:        var(--line);
  --fg-hi:       var(--fg);
  --fg-dim:      var(--fg-mute);
  --accent-dim:  var(--accent-mute);
  --danger:      var(--error);

  color-scheme: light;
}

/* prefers-reduced-motion: collapse durations */
@media (prefers-reduced-motion: reduce) {
  :root {
    --d-flash: 0ms;
    --d-fast:  0ms;
    --d-norm:  0ms;
    --d-slow:  0ms;
    --d-accordion: 0ms;
  }
}

export default function StubPlaceholder() {
  return (
    <div
      style={{
        minHeight: "60vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: "var(--s-6)",
        fontFamily: "var(--font-mono)",
        color: "var(--fg)",
        textAlign: "center",
      }}
    >
      <p style={{ maxWidth: "60ch" }}>
        this page is being rebuilt in v2. see /docs/v2_audit.md for the plan.
      </p>
    </div>
  );
}

