import type { CSSProperties, ReactNode } from "react";

type ContainerSize = "narrow" | "base" | "wide";

type ContainerProps = {
  children: ReactNode;
  size?: ContainerSize;
  as?: "div" | "section" | "article" | "main" | "header" | "footer";
  className?: string;
  style?: CSSProperties;
};

const MAX_WIDTH: Record<ContainerSize, string> = {
  narrow: "var(--container-narrow)",
  base: "var(--container-base)",
  wide: "var(--container-wide)",
};

export default function Container({
  children,
  size = "base",
  as: Tag = "div",
  className,
  style,
}: ContainerProps) {
  return (
    <>
      <Tag
        className={`v2-container v2-container--${size} ${className ?? ""}`.trim()}
        style={{
          maxWidth: MAX_WIDTH[size],
          marginInline: "auto",
          width: "100%",
          ...style,
        }}
      >
        {children}
      </Tag>
      <style jsx>{`
        .v2-container {
          padding-inline: var(--s-5);
        }
        @media (min-width: 768px) {
          .v2-container {
            padding-inline: var(--s-6);
          }
        }
      `}</style>
    </>
  );
}

