1	@import "../styles/tokens.css";
2	@import "../styles/reset.css";
3	@import "../styles/print.css";
4	
5	/* ----- keyframes ----- */
6	@keyframes operator-fade-up {
7	  from { opacity: 0; transform: translateY(8px); }
8	  to   { opacity: 1; transform: translateY(0); }
9	}
10	@keyframes operator-blink {
11	  0%, 100% { opacity: 1; }
12	  50%      { opacity: 0; }
13	}
14	@media (prefers-reduced-motion: reduce) {
15	  @keyframes operator-blink { 0%,100% { opacity: 1; } }
16	}
17	
18	.cursor-blink {
19	  display: inline-block;
20	  animation: operator-blink 1.6s steps(1, end) infinite;
21	}
22	
23	/* ----- palette ----- */
24	.palette-backdrop {
25	  position: fixed; inset: 0;
26	  background: rgba(0,0,0,0.55);
27	  z-index: var(--z-palette);
28	  animation: operator-fade-up var(--d-fast) var(--ease);
29	}
30	.palette {
31	  position: fixed;
32	  top: 14vh; left: 50%;
33	  transform: translateX(-50%);
34	  width: min(640px, 92vw);
35	  background: var(--bg-1);
36	  border: var(--border-hair);
37	  border-top: 1px solid var(--accent);
38	  z-index: calc(var(--z-palette) + 1);
39	  font-family: var(--font-mono);
40	  color: var(--fg);
41	  border-radius: 1px;
42	  display: flex; flex-direction: column;
43	  max-height: 70vh;
44	}
45	.palette-input-row {
46	  display: flex; align-items: center; gap: var(--s-3);
47	  height: 40px; padding: 0 var(--s-4);
48	}
49	.palette-chevron { color: var(--accent); }
50	.palette-input-row input {
51	  flex: 1; outline: none; caret-color: var(--accent);
52	  font-family: var(--font-mono); font-size: var(--t-sm-size);
53	}
54	.palette-input-row input::placeholder { color: var(--fg-mute); }
55	.palette-kbd {
56	  background: var(--bg-2); padding: 2px 6px; font-size: var(--t-xxs-size); color: var(--fg-mute);
57	}
58	.palette-divider { height: 1px; background: var(--rule); }
59	.palette-results { overflow: auto; }
60	.palette-row {
61	  display: grid;
62	  grid-template-columns: 24px 1fr auto;
63	  align-items: center;
64	  height: 36px; padding: 0 var(--s-4);
65	  font-size: var(--t-sm-size); cursor: pointer;
66	  border-left: 2px solid transparent;
67	}
68	.palette-row[data-selected="true"] {
69	  background: var(--bg-3);
70	  border-left-color: var(--accent);
71	}
72	.palette-glyph { color: var(--accent-dim); }
73	.palette-title { color: var(--fg); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
74	.palette-ctx { color: var(--fg-mute); font-size: var(--t-xs-size); padding-left: var(--s-4); white-space: nowrap; }
75	.palette-empty { padding: var(--s-4); color: var(--fg-mute); font-size: var(--t-xs-size); }
76	.palette-footer {
77	  height: 24px; padding: 0 var(--s-4);
78	  font-size: var(--t-xxs-size); color: var(--fg-mute);
79	  display: flex; align-items: center;
80	}
81	
82	/* ----- toast (R04: top-right, beneath the ⌘K key-cap) ----- */
83	.toast {
84	  position: fixed;
85	  top: calc(var(--keycap-size) + 24px);
86	  right: 16px;
87	  background: var(--bg-2); color: var(--fg); border: var(--border-hair);
88	  padding: var(--s-2) var(--s-4);
89	  font-family: var(--font-mono); font-size: var(--t-xs-size);
90	  z-index: var(--z-toast);
91	}
92	
93	/* ----- ⌘K key-cap affordance (R04: replaces status bar's hint) ----- */
94	.keycap {
95	  position: fixed;
96	  top: calc(var(--toprail-h) + 12px);
97	  right: 16px;
98	  width: var(--keycap-size); height: var(--keycap-size);
99	  display: inline-flex; align-items: center; justify-content: center;
100	  font-family: var(--font-mono);
101	  font-size: var(--t-xs-size);
102	  color: var(--fg-mute);
103	  background: var(--bg-1);
104	  border: var(--border-hair);
105	  cursor: pointer;
106	  z-index: var(--z-toast);
107	  transition: color var(--d-fast) var(--ease), border-color var(--d-fast) var(--ease);
108	}
109	.keycap:hover { color: var(--fg); border-color: var(--fg-mute); }
110	.keycap:focus-visible { outline: 2px solid var(--accent); outline-offset: 2px; }
111	
112	/* ----- accordion choreography (R01 + R02) ----- */
113	.panel { transition: flex-basis var(--d-accordion) var(--ease-accordion); }
114	.panel.is-animating { will-change: flex-basis; }
115	
116	/* Body content is always mounted (so layout is settled before width
117	   animates). Visibility is animation-driven, not transition-driven, so
118	   the entry repeats on every collapse→expand cycle including first mount. */
119	.panel-body {
120	  opacity: 0;
121	  transform: translateY(6px);
122	  pointer-events: none;
123	}
124	.panel[data-state="expanded"] .panel-body {
125	  pointer-events: auto;
126	  animation: operator-panel-in 260ms var(--ease-accordion) 260ms forwards;
127	}
128	.panel[data-state="collapsed"] .panel-body,
129	.panel[data-state="neutral"]   .panel-body {
130	  animation: operator-panel-out 180ms linear forwards;
131	}
132	
133	@keyframes operator-panel-in {
134	  from { opacity: 0; transform: translateY(6px); }
135	  to   { opacity: 1; transform: translateY(0); }
136	}
137	@keyframes operator-panel-out {
138	  from { opacity: 1; }
139	  to   { opacity: 0; }
140	}
141	
142	/* R02: spine label fades out IN PLACE when expanded. No travel, no morph. */
143	.spine-content {
144	  opacity: 1;
145	  transition: opacity 180ms linear;
146	}
147	.panel[data-state="expanded"] .spine-content {
148	  opacity: 0;
149	  pointer-events: none;
150	}
151	
152	@media (prefers-reduced-motion: reduce) {
153	  .panel { transition: none; }
154	  .panel-body { animation: none; opacity: 1; transform: none; pointer-events: auto; }
155	  .panel[data-state="collapsed"] .panel-body,
156	  .panel[data-state="neutral"]   .panel-body { opacity: 0; pointer-events: none; }
157	  .spine-content { transition: none; }
158	}
159	
160	/* ----- accordion mobile (<768px): stack vertically ----- */
161	@media (max-width: 767px) {
162	  .accordion {
163	    flex-direction: column !important;
164	    height: auto !important;
165	    min-height: calc(100vh - var(--statusbar-h));
166	  }
167	  .accordion .panel {
168	    width: 100% !important;
169	    border-right: none !important;
170	    border-bottom: var(--border-hair);
171	    flex: 0 0 auto !important;
172	    flex-direction: column !important;
173	  }
174	  .accordion .panel-spine {
175	    flex-direction: row !important;
176	    height: 56px !important;
177	    width: 100% !important;
178	    justify-content: flex-start !important;
179	    padding: 0 var(--s-4) !important;
180	    gap: var(--s-4);
181	  }
182	  .accordion .panel .panel-spine span[aria-hidden="true"] {
183	    writing-mode: horizontal-tb !important;
184	    transform: none !important;
185	    white-space: normal;
186	  }
187	}
188	
189	/* ----- generic dossier chrome ----- */
190	.dossier { padding: var(--s-6) var(--s-7); max-width: 1200px; margin: 0 auto; }
191	.dossier-header { font-family: var(--font-mono); margin-bottom: var(--s-6); }
192	.dossier-rule {
193	  display: flex; align-items: baseline; justify-content: space-between;
194	  border-bottom: var(--border-hair); padding-bottom: var(--s-2); margin-bottom: var(--s-2);
195	  color: var(--fg-mute);
196	}
197	.dossier-title { color: var(--fg-hi); font-size: var(--t-md-size); }
198	.dossier-bread { color: var(--fg-dim); font-size: var(--t-xs-size); }
199	.dossier-sub   { color: var(--fg-dim); font-size: var(--t-sm-size); margin-top: var(--s-2); }
200	
201	.dossier-grid {
202	  display: grid;
203	  grid-template-columns: 280px 1fr;
204	  gap: var(--s-7);
205	}
206	@media (max-width: 1024px) {
207	  .dossier-grid { grid-template-columns: 1fr; }
208	}
209	.metadata-pane { font-family: var(--font-mono); font-size: var(--t-sm-size); color: var(--fg); }
210	.metadata-pane .row { display: grid; grid-template-columns: 96px 1fr; gap: var(--s-3); padding: 4px 0; }
211	.metadata-pane .k   { color: var(--fg-mute); text-align: right; text-transform: uppercase; }
212	.metadata-pane .v   { color: var(--fg); }
213	
214	.synopsis { font-family: var(--font-sans); font-size: var(--t-md-size); line-height: var(--t-md-lh); color: var(--fg); max-width: var(--measure-prose); }
215	.synopsis p + p { margin-top: var(--s-4); }
216	
217	.artifacts { margin-top: var(--s-7); font-family: var(--font-mono); }
218	.artifacts-h { color: var(--fg-mute); border-bottom: var(--border-hair); padding-bottom: var(--s-2); margin-bottom: var(--s-3); }
219	.artifacts li { display: grid; grid-template-columns: 120px 1fr 1em; gap: var(--s-3); padding: 2px 0; font-size: var(--t-sm-size); }
220	.artifacts .k { color: var(--fg-mute); }
221	.artifacts .l { color: var(--fg); }
222	.artifacts a:hover { text-decoration: underline; text-decoration-thickness: 1px; text-underline-offset: 3px; }
223	
224	/* ----- projects table ----- */
225	.projects-table {
226	  width: 100%; border-collapse: collapse;
