import type { CSSProperties, ReactNode } from "react";

type ContainerSize = "narrow" | "base" | "wide";

type ContainerProps = {
  children: ReactNode;
  size?: ContainerSize;
  as?: "div" | "section" | "article" | "main" | "header" | "footer";
  className?: string;
  style?: CSSProperties;
};

const MAX_WIDTH: Record<ContainerSize, string> = {
  narrow: "var(--container-narrow)",
  base: "var(--container-base)",
  wide: "var(--container-wide)",
};

const RESPONSIVE_PADDING_CSS = `
.v2-container{padding-inline:var(--s-5)}
@media (min-width:768px){.v2-container{padding-inline:var(--s-6)}}
`;

export default function Container({
  children,
  size = "base",
  as: Tag = "div",
  className,
  style,
}: ContainerProps) {
  const cls = ["v2-container", `v2-container--${size}`, className]
    .filter(Boolean)
    .join(" ");
  return (
    <Tag
      className={cls}
      style={{
        maxWidth: MAX_WIDTH[size],
        marginInline: "auto",
        width: "100%",
        ...style,
      }}
    >
      <style
        // eslint-disable-next-line react/no-danger
        dangerouslySetInnerHTML={{ __html: RESPONSIVE_PADDING_CSS }}
      />
      {children}
    </Tag>
  );
}

